pub struct GraphExpandRetriever {
    store: Arc<dyn QueryableStore>,
    engine: Arc<dyn InferenceEngine>,
    graph: Arc<dyn GraphStore>,
    alpha: f32,
}
impl GraphExpandRetriever {
    pub fn new(
        store: Arc<dyn QueryableStore>,
        engine: Arc<dyn InferenceEngine>,
        graph: Arc<dyn GraphStore>,
        alpha: f32,
    ) -> Self {
        Self {
            store,
            engine,
            graph,
            alpha,
        }
    }
}
